import requests

def update_data(url: str, data: dict):
    headers = {
        "Content-Type": "application/json"
    }

    try:
        response = requests.put(url, json=data, headers=headers)
        response.raise_for_status()  # HTTP 4xx/5xx hataları için istisna fırlatır

        if response.content:
            return response.json()
        else:
            # Yanıt içeriği yoksa (örn: 204 No Content), işlemi başarılı sayıp None dönebiliriz.
            return None 
    except requests.exceptions.RequestException:
        return None
    except ValueError: # response.json() çağrısında JSON çözümleme hatası olursa
        return None
